import{_ as a,o as i,c as e,S as r}from"./chunks/framework.C6RQlTYc.js";const g=JSON.parse('{"title":"过拟合与正则化","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_14-overfitting_regularization.md","filePath":"直击概念/17ai/s_ai_14-overfitting_regularization.md","lastUpdated":1778207238000}'),o={name:"直击概念/17ai/s_ai_14-overfitting_regularization.md"};function l(n,t,d,h,s,u){return i(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="过拟合与正则化" tabindex="-1">过拟合与正则化 <a class="header-anchor" href="#过拟合与正则化" aria-label="Permalink to &quot;过拟合与正则化&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><h3 id="过拟合-overfitting" tabindex="-1">过拟合（Overfitting） <a class="header-anchor" href="#过拟合-overfitting" aria-label="Permalink to &quot;过拟合（Overfitting）&quot;">​</a></h3><p>过拟合是指模型在<strong>训练数据上表现优异</strong>，但在<strong>新数据（测试集）上表现很差</strong>。模型&quot;记住&quot;了训练数据中的噪声和特异性模式，而不是学习到可泛化的规律。</p><h3 id="欠拟合-underfitting" tabindex="-1">欠拟合（Underfitting） <a class="header-anchor" href="#欠拟合-underfitting" aria-label="Permalink to &quot;欠拟合（Underfitting）&quot;">​</a></h3><p>模型连训练数据上的规律都没学到，训练集和测试集的表现都差。</p><h2 id="偏差-方差权衡-bias-variance-tradeoff" tabindex="-1">偏差-方差权衡（Bias-Variance Tradeoff） <a class="header-anchor" href="#偏差-方差权衡-bias-variance-tradeoff" aria-label="Permalink to &quot;偏差-方差权衡（Bias-Variance Tradeoff）&quot;">​</a></h2><table><thead><tr><th>状态</th><th>偏差（Bias）</th><th>方差（Variance）</th><th>表现</th></tr></thead><tbody><tr><td>欠拟合</td><td>高</td><td>低</td><td>都差</td></tr><tr><td>适中</td><td>适中</td><td>适中</td><td>都好</td></tr><tr><td>过拟合</td><td>低</td><td>高</td><td>训练好，测试差</td></tr></tbody></table><ul><li><strong>偏差</strong>：模型预测与真实值的平均偏离度（模型学得&quot;对不对&quot;）</li><li><strong>方差</strong>：模型在不同数据集上的预测波动（模型&quot;稳不稳定&quot;）</li></ul><h2 id="如何识别过拟合" tabindex="-1">如何识别过拟合 <a class="header-anchor" href="#如何识别过拟合" aria-label="Permalink to &quot;如何识别过拟合&quot;">​</a></h2><ul><li>训练损失持续下降，但验证损失先降后升（经典信号）</li><li>测试集指标远差于训练集</li><li>模型记住了训练数据的特异性细节</li></ul><h2 id="正则化方法" tabindex="-1">正则化方法 <a class="header-anchor" href="#正则化方法" aria-label="Permalink to &quot;正则化方法&quot;">​</a></h2><h3 id="dropout" tabindex="-1">Dropout <a class="header-anchor" href="#dropout" aria-label="Permalink to &quot;Dropout&quot;">​</a></h3><p>训练时<strong>随机丢弃</strong>一定比例的神经元（通常 10%~50%），强迫网络学习冗余表示。相当于同时在训练大量子网络并取平均。</p><ul><li>仅在训练时启用，推理时关闭</li><li>是防止过拟合最常用的方法之一</li></ul><h3 id="l1-l2-正则化-权重衰减" tabindex="-1">L1 / L2 正则化（权重衰减） <a class="header-anchor" href="#l1-l2-正则化-权重衰减" aria-label="Permalink to &quot;L1 / L2 正则化（权重衰减）&quot;">​</a></h3><p>在损失函数中加上参数大小的惩罚项：</p><ul><li><strong>L1（Lasso）</strong>：L = L_original + λ·Σ|W| → 倾向产生稀疏权重</li><li><strong>L2（Ridge / 权重衰减）</strong>：L = L_original + λ·ΣW² → 倾向产生小权重</li></ul><p>现代 LLM 中 L2 权重衰减（Weight Decay）是标配。</p><h3 id="早停-early-stopping" tabindex="-1">早停（Early Stopping） <a class="header-anchor" href="#早停-early-stopping" aria-label="Permalink to &quot;早停（Early Stopping）&quot;">​</a></h3><p>监控验证集损失，当不再下降时停止训练。</p><h3 id="数据增强-data-augmentation" tabindex="-1">数据增强（Data Augmentation） <a class="header-anchor" href="#数据增强-data-augmentation" aria-label="Permalink to &quot;数据增强（Data Augmentation）&quot;">​</a></h3><p>对数据做微小的随机变换（如文本中的同义词替换、回译等），增大有效训练数据量。</p><h3 id="批量归一化-batch-normalization" tabindex="-1">批量归一化（Batch Normalization） <a class="header-anchor" href="#批量归一化-batch-normalization" aria-label="Permalink to &quot;批量归一化（Batch Normalization）&quot;">​</a></h3><p>对每一层的输出做归一化，稳定训练过程，也有一定的正则化效果。</p><h2 id="验证集-validation-set" tabindex="-1">验证集（Validation Set） <a class="header-anchor" href="#验证集-validation-set" aria-label="Permalink to &quot;验证集（Validation Set）&quot;">​</a></h2><p>将数据分为三部分：</p><table><thead><tr><th>数据集</th><th>用途</th><th>比例</th></tr></thead><tbody><tr><td>训练集</td><td>训练模型参数</td><td>~70%-80%</td></tr><tr><td>验证集</td><td>调超参数、监控过拟合</td><td>~10%-15%</td></tr><tr><td>测试集</td><td>最终评估泛化能力</td><td>~10%-15%</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>过拟合的典型信号是什么？</li><li>Dropout 为什么能防止过拟合？</li><li>训练集、验证集、测试集各起什么作用？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Overfitting" target="_blank" rel="noreferrer">Overfitting - Wikipedia</a></li><li><a href="https://www.deeplearning.ai/" target="_blank" rel="noreferrer">Regularization in Deep Learning - DeepLearning.AI</a></li></ul>',32)])])}const p=a(o,[["render",l]]);export{g as __pageData,p as default};
